type (
    PauseSubscriptionRequest  = struct{ ID models.NamespacedID }
    PauseSubscriptionResponse = api.Subscription
    PauseSubscriptionParams   = struct{ ID string }
    PauseSubscriptionHandler  = httptransport.HandlerWithArgs[PauseSubscriptionRequest, PauseSubscriptionResponse, PauseSubscriptionParams]
)
func (h *handler) PauseSubscription() PauseSubscriptionHandler {
    return httptransport.NewHandlerWithArgs(
        func(ctx context.Context, r *http.Request, params PauseSubscriptionParams) (PauseSubscriptionRequest, error) {
            ns, err := h.resolveNamespace(ctx)
            if err != nil { return PauseSubscriptionRequest{}, err }
            return PauseSubscriptionRequest{ID: models.NamespacedID{Namespace: ns, ID: params.ID}}, nil
        },
        func(ctx context.Context, req PauseSubscriptionRequest) (PauseSubscriptionResponse, error) { /* delegate to workflow */ },
        commonhttp.JSONResponseEncoder[PauseSubscriptionResponse],
        httptransport.AppendOptions(h.Options, httptransport.WithOperationName("pauseSubscription"), httptransport.WithErrorEncoder(errorEncoder()))...,
    )
}

func (s *service) Schedule(ctx context.Context, request plansubscription.ScheduleSubscriptionRequest) (subscription.Subscription, error) {
    var def subscription.Subscription
    if err := request.PlanInput.Validate(); err != nil { return def, models.NewGenericValidationError(err) }
    var plan subscription.Plan
    if request.PlanInput.AsInput() != nil {
        p, err := PlanFromPlanInput(*request.PlanInput.AsInput())
        if err != nil { return def, err }
        plan = p
    } else if request.PlanInput.AsRef() != nil {
        p, err := s.getPlanByVersion(ctx, request.WorkflowInput.Namespace, *request.PlanInput.AsRef())
        if err != nil { return def, err }
        plan = PlanFromPlan(*p)
    }
    // delegate to s.WorkflowService.CreateFromPlan
    return def, nil
}
